open my $fh, '<', $file or die "Could not open '$file': $!";

my %word_count;
while (my $line = <$fh>) {
    chomp $line;
    my @words = split /\s+/, lc($line);
    foreach my $word (@words) {
        $word_count{$word}++;
    }
}

close $fh;

